def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        base_dir = os.path.realpath(dir_path)
        target = os.path.realpath(os.path.join(base_dir, filename))
        if os.path.commonpath([base_dir, target]) != base_dir:
