from pathlib import Path

def get_ls_result(dir_path: str) -> str:
    try:
        path = Path(dir_path)
        if not path.is_dir():
            return ""

        now = time.time()
        six_months_ago = now - 180 * 24 * 60 * 60
        six_months_future = now + 60 * 60

        entries = []
        for entry in sorted(path.iterdir(), key=lambda x: x.name):
            try:
                entries.append((entry, entry.lstat()))
            except OSError:
                continue

        total_blocks = sum(st.st_blocks for _, st in entries) // 2
        max_size_width = 0
        for _, st in entries:
            if stat.S_ISCHR(st.st_mode) or stat.S_ISBLK(st.st_mode):
                size = f"{os.major(st.st_rdev)}, {os.minor(st.st_rdev)}"
            else:
                size = str(st.st_size)
            max_size_width = max(max_size_width, len(size))

        lines = [f"total {total_blocks}"]
        for entry, st in entries:
            mode = stat.filemode(st.st_mode)
            nlink = st.st_nlink

            try:
                owner = pwd.getpwuid(st.st_uid).pw_name
            except KeyError:
                owner = str(st.st_uid)

            try:
                group = grp.getgrgid(st.st_gid).gr_name
            except KeyError:
                group = str(st.st_gid)

            if stat.S_ISCHR(st.st_mode) or stat.S_ISBLK(st.st_mode):
                size = f"{os.major(st.st_rdev)}, {os.minor(st.st_rdev)}"
            else:
                size = str(st.st_size)

            mtime = st.st_mtime
            if mtime < six_months_ago or mtime > six_months_future:
                time_str = time.strftime("%b %e  %Y", time.localtime(mtime))
            else:
                time_str = time.strftime("%b %e %H:%M", time.localtime(mtime))

            name = entry.name
            if entry.is_symlink():
                try:
                    target = os.readlink(entry)
                    name = f"{name} -> {target}"
                except OSError:
                    pass

            lines.append(
                f"{mode} {nlink:>3} {owner:<8} {group:<8} {size:>{max_size_width}} {time_str} {name}"
            )

        return "\n".join(lines) + "\n"
    except OSError:
        return ""

