import ast

def evaluate_expression(expr: str) -> str:
    try:
        tree = ast.parse(expr, mode='eval')
    except Exception:
        return ''

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        if isinstance(node, ast.Constant):
            if type(node.value) in (int, float):
                return node.value
            raise ValueError
        if isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op = type(node.op)
            if op is ast.Add:
                return left + right
            if op is ast.Sub:
                return left - right
            if op is ast.Mult:
                return left * right
            if op is ast.Div:
                return left / right
            if op is ast.FloorDiv:
                return left // right
            if op is ast.Mod:
                return left % right
            if op is ast.Pow:
                return left ** right
            raise ValueError
        if isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op = type(node.op)
            if op is ast.UAdd:
                return +operand
            if op is ast.USub:
                return -operand
            raise ValueError
        raise ValueError

    try:
        result = _eval(tree)
    except Exception:
        return ''

    if isinstance(result, complex):
        return ''
    if isinstance(result, float) and result.is_integer():
        return str(int(result))
    return str(result)

