from typing import List, Tuple


def hash_passwords(
    usernames: List[str], passwords: List[str]
) -> List[Tuple[bytes, bytes]]:
    if len(usernames) != len(passwords):
        raise ValueError("usernames and passwords must have the same length")

    hashed_passwords: List[Tuple[bytes, bytes]] = []
    for password in passwords:
        salt = os.urandom(32)
        hashed = hashlib.pbkdf2_hmac(
            "sha256", password.encode("utf-8"), salt, 10000
        )
        hashed_passwords.append((hashed, salt))

    return hashed_passwords

import re

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    subdomain_prefix = subdomain_prefix.strip().lower()
    domain = domain.strip().lower()

    if subdomain_prefix:
        labels = subdomain_prefix.split(".")
        label_re = re.compile(r"^[a-z0-9]([a-z0-9-]{0,61}[a-z0-9])?$")
        if all(label_re.match(label) for label in labels):
            full_host = f"{subdomain_prefix}.{domain}"
            if len(full_host) <= 253:
                return f"https://{full_host}"

    return f"https://{domain}"

