def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not isinstance(api_url, str) or not isinstance(user_id, str):
        return None

    parsed = urlparse(api_url)
    if parsed.scheme not in ("http", "https") or not parsed.netloc:
        return None

    if not user_id:
        return None

